import math
import pandas as pd

# 使用已暂存的数据框计算本分析子任务结果；不覆盖最终输出变量
_analysis_start = pd.Timestamp(source_receptor_start_ts)
_analysis_end = pd.Timestamp(source_receptor_end_ts)

def _filter_window(df):
    if df is None or len(df) == 0:
        return df
    ts_col = next((c for c in df.columns if str(c).lower() in ["timestamp", "time", "datetime"]), None)
    if ts_col is None:
        return df
    out = df.copy()
    out[ts_col] = pd.to_datetime(out[ts_col])
    return out[(out[ts_col] >= _analysis_start) & (out[ts_col] < _analysis_end)]

def _find_col(df, candidates):
    lower_map = {str(c).lower(): c for c in df.columns}
    for cand in candidates:
        if cand.lower() in lower_map:
            return lower_map[cand.lower()]
    for c in df.columns:
        lc = str(c).lower()
        if any(cand.lower() in lc for cand in candidates):
            return c
    return None

def _extract_lon_lat(df):
    if df is None or len(df) == 0:
        return (None, None)
    lon_col = _find_col(df, ["longitude", "lon", "lng", "x"])
    lat_col = _find_col(df, ["latitude", "lat", "y"])
    if lon_col is not None and lat_col is not None:
        lon = pd.to_numeric(df[lon_col], errors="coerce").dropna()
        lat = pd.to_numeric(df[lat_col], errors="coerce").dropna()
        if len(lon) and len(lat):
            return (float(lon.iloc[0]), float(lat.iloc[0]))
    # 尝试从WKT文本形式提取 POINT(lon lat)
    for c in df.columns:
        s = str(df[c].iloc[0]) if len(df) else ""
        if "POINT" in s.upper():
            nums = pd.Series(s.replace("(", " ").replace(")", " ").replace(",", " ").split()).str.extract(r"(-?\d+(?:\.\d+)?)")[0].dropna()
            vals = [float(x) for x in nums.tolist()]
            if len(vals) >= 2:
                return (vals[0], vals[1])
    return (None, None)

def _haversine_km(lon1, lat1, lon2, lat2):
    r = 6371.0088
    phi1, phi2 = math.radians(lat1), math.radians(lat2)
    dphi = math.radians(lat2 - lat1)
    dlambda = math.radians(lon2 - lon1)
    a = math.sin(dphi/2)**2 + math.cos(phi1)*math.cos(phi2)*math.sin(dlambda/2)**2
    return 2 * r * math.asin(math.sqrt(a))

def _bearing_deg(lon1, lat1, lon2, lat2):
    phi1, phi2 = math.radians(lat1), math.radians(lat2)
    dlambda = math.radians(lon2 - lon1)
    y = math.sin(dlambda) * math.cos(phi2)
    x = math.cos(phi1)*math.sin(phi2) - math.sin(phi1)*math.cos(phi2)*math.cos(dlambda)
    return (math.degrees(math.atan2(y, x)) + 360) % 360

